package com.aadil.jobtracker.responses;import lombok.Getter;import java.util.List;@Getterpublic class PagedResponse<T>  {    private final List<T> contents;    private final int page;    private final int pageSize;    private final int totalPages;    private final long totalElements;    private final boolean lastPage;    public PagedResponse(List<T> contents, int page, int pageSize, int totalPages, long totalElements, boolean lastPage) {        this.contents = contents;        this.pageSize = pageSize;        this.totalPages = totalPages;        this.page = page;        this.totalElements = totalElements;        this.lastPage = lastPage;    }}